import{_ as n,o as a,c as t,a2 as i}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse(`{"title":"Chapter 3: Understanding LLMs","description":"How language models work from an agent builder's perspective — tokens, APIs, tool use, streaming, and prompt engineering.","frontmatter":{"title":"Chapter 3: Understanding LLMs","description":"How language models work from an agent builder's perspective — tokens, APIs, tool use, streaming, and prompt engineering."},"headers":[],"relativePath":"learn/linear/03-understanding-llms/index.md","filePath":"learn/linear/03-understanding-llms/index.md"}`),r={name:"learn/linear/03-understanding-llms/index.md"};function l(s,e,o,d,m,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="understanding-llms" tabindex="-1">Understanding LLMs <a class="header-anchor" href="#understanding-llms" aria-label="Permalink to &quot;Understanding LLMs&quot;">​</a></h1><p>Building a coding agent requires a practical understanding of how large language models work — not as a researcher studying architectures, but as an engineer who needs to know what goes over the wire, how tokens are counted, and why the model sometimes does unexpected things. This chapter provides exactly that level of understanding.</p><p>We start with the fundamentals: what tokens are, how context windows constrain your design, and how temperature affects output. We then dive deep into the API layer, covering message formats, the tool use protocol, function calling, and streaming. You will learn the specific anatomy of both Anthropic and OpenAI APIs, because a good agent should be provider-agnostic.</p><p>The chapter culminates with prompt engineering techniques specifically tailored for agent systems. Writing a system prompt for an agent is fundamentally different from writing one for a chatbot — you need to guide the model toward tool use, structured output, and multi-step reasoning. By the end, you will understand the LLM not as a black box but as a well-characterized component with known behaviors, limitations, and configuration surfaces.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Explain how tokenization works and why token counts matter for agent design</li><li>Understand context window limits and strategies for managing conversation length</li><li>Implement the tool use protocol including function calling and result handling</li><li>Work with both Anthropic and OpenAI API formats for messages, tools, and streaming</li><li>Apply prompt engineering techniques that improve agent reliability and tool use accuracy</li><li>Make informed decisions about model selection, temperature, and sampling parameters</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/03-understanding-llms/01-what-are-llms.html">What Are LLMs</a></li><li><a href="/linear/03-understanding-llms/02-tokens-and-tokenization.html">Tokens and Tokenization</a></li><li><a href="/linear/03-understanding-llms/03-context-windows.html">Context Windows</a></li><li><a href="/linear/03-understanding-llms/04-temperature-and-sampling.html">Temperature and Sampling</a></li><li><a href="/linear/03-understanding-llms/05-system-prompts.html">System Prompts</a></li><li><a href="/linear/03-understanding-llms/06-message-formats.html">Message Formats</a></li><li><a href="/linear/03-understanding-llms/07-tool-use-protocol.html">Tool Use Protocol</a></li><li><a href="/linear/03-understanding-llms/08-function-calling-deep-dive.html">Function Calling Deep Dive</a></li><li><a href="/linear/03-understanding-llms/09-json-mode.html">JSON Mode</a></li><li><a href="/linear/03-understanding-llms/10-streaming-protocol.html">Streaming Protocol</a></li><li><a href="/linear/03-understanding-llms/11-api-anatomy-anthropic.html">API Anatomy Anthropic</a></li><li><a href="/linear/03-understanding-llms/12-api-anatomy-openai.html">API Anatomy OpenAI</a></li><li><a href="/linear/03-understanding-llms/13-rate-limits-and-pricing.html">Rate Limits and Pricing</a></li><li><a href="/linear/03-understanding-llms/14-prompt-engineering-for-agents.html">Prompt Engineering for Agents</a></li><li><a href="/linear/03-understanding-llms/15-model-selection.html">Model Selection</a></li><li><a href="/linear/03-understanding-llms/16-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 1 (understanding of what agents do)</li></ul>',10)])])}const c=n(r,[["render",l]]);export{g as __pageData,c as default};
